// Performance Logging Middleware with caching
const performanceLogger = (req, res, next) => {
    const start = new Date().getTime();
    performanceLoggerCache[req.method] = performanceLoggerCache[req.method] || [];
    performanceLoggerCache[req.method].push({ startTime: start });
    next();
    res.on('finish', () => {
        const diff = new Date().getTime() - start;
        performanceLoggerCache[req.method].push({ end: new Date().getTime(), duration: diff });
        const averages = performanceLoggerCache[req.method].reduce((acc, curr, i, arr) => {
            if (i !== arr.length - 1) {
                acc.duration += arr[i + 1].duration - curr.duration;
            }
            // Store last duration in case of errors
            else {
                acc.duration += arr[i].duration - curr.duration;
            }
            return acc;
        }, { duration: 0 });
        const methodAvgDuration = averages.duration / (performanceLoggerCache[req.method].length - 1 || 1);
        console.log(`Method: ${req.method}, Average Duration: ${methodAvgDuration}ms`);
        fs.appendFileSync(LOG_FILE, JSON.stringify(performanceLoggerCache[req.method]) + "\n");
    });
};
