    const execOptions = {
        cwd: agentDir,
        env: { ...process.env, PATH: process.env.PATH },
    };

    try {
        const output = await new Promise((resolve, reject) => {
            execSync(pythonCmd, execOptions, (error, stdout, stderr) => {
                if (error) {
                    reject(error);
                } else {
                    resolve(stdout.toString());
                }
            });
        });
        console.log(`✅ Scan Output: ${output}`);
